import urllib.request, json
def gh_raw(path, ref="fix/keychain-persistence-p0"):
    url = f"https://raw.githubusercontent.com/jakobtfaber/undermind-mcp/{ref}/{path}"
    try:
        with urllib.request.urlopen(url, timeout=10) as r:
            return r.read().decode('utf-8','replace')
    except Exception as e:
        return f"ERROR: {e}"

for p in ["tests/test_cli.py","tests/test_server.py"]:
    txt = gh_raw(p)
    print("===",p,"===")
    if txt.startswith("ERROR"):
        print(txt)
    else:
        print("keychain_enabled" in txt, txt.count("keychain_enabled"))
